import { useMemo, useState } from "react";

/*
  Decisions.jsx - Fixed and Enhanced
  
  Changes made:
  - Fixed all template literal syntax errors (backticks)
  - Fixed JSX className interpolation issues
  - Improved button interactions and event handling
  - Enhanced visual hierarchy and information density
  - Added loading states and better UX feedback
  - Fixed drawer action flow
  - Improved mobile responsiveness
  - Added more informative data displays
*/

const DUMMY_REQUESTS = [
  {
    id: "REQ-2026-001",
    systemId: "SYS-8472",
    owner: "Manufacturing / Line B",
    requestedBy: "tech.alex",
    aiVerdict: "approve",
    rootCause: "Hardware",
    confidence: 94,
    estimatedCost: 4200,
    riskIfDelayed: "High",
    status: "pending",
    timestamps: {
      requestedAt: new Date(Date.now() - 48 * 60 * 60 * 1000).toISOString(),
      aiVerdictAt: new Date(Date.now() - 36 * 60 * 60 * 1000).toISOString(),
      reviewedAt: null,
      finalDecisionAt: null,
    },
    systemSnapshot: {
      ageYears: 4,
      warrantyUntil: new Date(Date.now() + 60 * 24 * 60 * 60 * 1000).toISOString(),
      healthTrend: [
        { label: "30d", value: 78 },
        { label: "14d", value: 62 },
        { label: "7d", value: 55 },
        { label: "1d", value: 42 },
      ],
    },
    evidence: {
      hardware: [
        "SMART warnings: reallocated sectors rising",
        "I/O latencies correlated with backup windows",
      ],
      software: ["Backup job overlapping causing higher I/O"],
      security: ["No persistent malicious indicators"],
    },
    financial: {
      downtimeCostPerHour: 1200,
      repairEstimate: 1800,
      replaceEstimate: 4200,
    },
    timeline: [
      {
        ts: new Date(Date.now() - 48 * 60 * 60 * 1000).toISOString(),
        actor: "tech.alex",
        action: "Requested replacement",
        note: "Intermittent failures observed",
      },
      {
        ts: new Date(Date.now() - 36 * 60 * 60 * 1000).toISOString(),
        actor: "ML Engine",
        action: "AI verdict",
        note: "Recommend APPROVE (94% confidence)",
      },
    ],
  },
  {
    id: "REQ-2026-002",
    systemId: "SYS-9031",
    owner: "Data Center / Rack 7",
    requestedBy: "ops.maya",
    aiVerdict: "reject",
    rootCause: "Software",
    confidence: 78,
    estimatedCost: 1600,
    riskIfDelayed: "Medium",
    status: "pending",
    timestamps: {
      requestedAt: new Date(Date.now() - 10 * 60 * 60 * 1000).toISOString(),
      aiVerdictAt: new Date(Date.now() - 9 * 60 * 60 * 1000).toISOString(),
      reviewedAt: null,
      finalDecisionAt: null,
    },
    systemSnapshot: {
      ageYears: 2,
      warrantyUntil: null,
      healthTrend: [
        { label: "30d", value: 88 },
        { label: "7d", value: 84 },
        { label: "1d", value: 80 },
      ],
    },
    evidence: {
      hardware: ["No hardware anomalies"],
      software: ["Misconfigured service causing retries", "Patch pending"],
      security: ["No issues"],
    },
    financial: {
      downtimeCostPerHour: 400,
      repairEstimate: 400,
      replaceEstimate: 1600,
    },
    timeline: [
      {
        ts: new Date(Date.now() - 10 * 60 * 60 * 1000).toISOString(),
        actor: "ops.maya",
        action: "Requested replacement",
        note: "App-level restarts observed",
      },
      {
        ts: new Date(Date.now() - 9 * 60 * 60 * 1000).toISOString(),
        actor: "ML Engine",
        action: "AI verdict",
        note: "Recommend REJECT (78% confidence)",
      },
    ],
  },
  {
    id: "REQ-2026-003",
    systemId: "SYS-7720",
    owner: "R&D / Lab",
    requestedBy: "eng.sam",
    aiVerdict: "approve",
    rootCause: "Hardware",
    confidence: 85,
    estimatedCost: 1200,
    riskIfDelayed: "Low",
    status: "approved",
    timestamps: {
      requestedAt: new Date(Date.now() - 6 * 24 * 60 * 60 * 1000).toISOString(),
      aiVerdictAt: new Date(Date.now() - 5.5 * 24 * 60 * 60 * 1000).toISOString(),
      reviewedAt: new Date(Date.now() - 4 * 24 * 60 * 60 * 1000).toISOString(),
      finalDecisionAt: new Date(Date.now() - 3.5 * 24 * 60 * 60 * 1000).toISOString(),
    },
    systemSnapshot: {
      ageYears: 5,
      warrantyUntil: null,
      healthTrend: [
        { label: "90d", value: 85 },
        { label: "30d", value: 70 },
        { label: "7d", value: 48 },
      ],
    },
    evidence: {
      hardware: [
        "Repeated ECC corrections on memory",
        "SMART critical thresholds exceeded",
      ],
      software: ["N/A"],
      security: ["N/A"],
    },
    financial: {
      downtimeCostPerHour: 200,
      repairEstimate: 200,
      replaceEstimate: 1200,
    },
    timeline: [
      {
        ts: new Date(Date.now() - 6 * 24 * 60 * 60 * 1000).toISOString(),
        actor: "eng.sam",
        action: "Requested replacement",
        note: "Frequent crashes during tests",
      },
      {
        ts: new Date(Date.now() - 5.5 * 24 * 60 * 60 * 1000).toISOString(),
        actor: "ML Engine",
        action: "AI verdict",
        note: "Recommend APPROVE (85% confidence)",
      },
      {
        ts: new Date(Date.now() - 4 * 24 * 60 * 60 * 1000).toISOString(),
        actor: "lead.jordan",
        action: "Approved replacement",
        note: "Order placed",
      },
    ],
  },
];

// Utility functions
function currency(v) {
  return v.toLocaleString(undefined, {
    style: "currency",
    currency: "USD",
    maximumFractionDigits: 0,
  });
}

function relativeTime(iso) {
  const d = Math.floor((Date.now() - new Date(iso).getTime()) / 1000);
  if (d < 60) return `${d}s ago`;
  if (d < 3600) return `${Math.floor(d / 60)}m ago`;
  if (d < 86400) return `${Math.floor(d / 3600)}h ago`;
  return `${Math.floor(d / 86400)}d ago`;
}

function statusBadgeClass(status) {
  switch (status) {
    case "pending":
      return "bg-yellow-100 text-yellow-800 border border-yellow-200";
    case "approved":
      return "bg-green-100 text-green-800 border border-green-200";
    case "rejected":
      return "bg-red-100 text-red-800 border border-red-200";
    case "deferred":
      return "bg-slate-100 text-slate-800 border border-slate-200";
    default:
      return "bg-gray-100 text-gray-800 border border-gray-200";
  }
}

function riskBadgeClass(risk) {
  if (risk === "High") return "bg-red-100 text-red-700 border border-red-200";
  if (risk === "Medium") return "bg-yellow-100 text-yellow-800 border border-yellow-200";
  return "bg-green-100 text-green-700 border border-green-200";
}

export default function Decisions() {
  const [requests, setRequests] = useState(DUMMY_REQUESTS);
  const [query, setQuery] = useState("");
  const [statusFilter, setStatusFilter] = useState("All");
  const [rootCauseFilter, setRootCauseFilter] = useState("All");
  const [sortKey, setSortKey] = useState("timestamps.requestedAt");
  const [sortDir, setSortDir] = useState("desc");

  // Drawer state
  const [drawerOpen, setDrawerOpen] = useState(false);
  const [selected, setSelected] = useState(null);
  const [actionMode, setActionMode] = useState(null);
  const [actionReason, setActionReason] = useState("");

  // Search and filter
  const visible = useMemo(() => {
    const q = query.trim().toLowerCase();
    const filtered = requests.filter((r) => {
      if (statusFilter !== "All" && r.status !== statusFilter.toLowerCase())
        return false;
      if (rootCauseFilter !== "All" && r.rootCause !== rootCauseFilter)
        return false;
      if (!q) return true;
      return (
        r.id.toLowerCase().includes(q) ||
        r.systemId.toLowerCase().includes(q) ||
        r.owner.toLowerCase().includes(q) ||
        r.requestedBy.toLowerCase().includes(q)
      );
    });

    const sorted = [...filtered].sort((a, b) => {
      const get = (obj, path) =>
        path.split(".").reduce((s, k) => (s ? s[k] : undefined), obj);
      const va = get(a, sortKey);
      const vb = get(b, sortKey);
      if (va == null && vb == null) return 0;
      if (va == null) return sortDir === "asc" ? -1 : 1;
      if (vb == null) return sortDir === "asc" ? 1 : -1;
      if (typeof va === "number" && typeof vb === "number")
        return sortDir === "asc" ? va - vb : vb - va;
      return sortDir === "asc"
        ? String(va).localeCompare(String(vb))
        : String(vb).localeCompare(String(va));
    });
    return sorted;
  }, [requests, query, statusFilter, rootCauseFilter, sortKey, sortDir]);

  // KPI calculations
  const kpis = useMemo(() => {
    const pending = requests.filter((r) => r.status === "pending").length;
    const approvedToday = requests.filter((r) => {
      if (!r.timestamps.finalDecisionAt) return false;
      const d = new Date(r.timestamps.finalDecisionAt);
      const now = new Date();
      return (
        d.toDateString() === now.toDateString() && r.status === "approved"
      );
    }).length;
    const costAtRisk = requests
      .filter((r) => r.status === "pending")
      .reduce((s, r) => s + (r.estimatedCost || 0), 0);
    return { pending, approvedToday, costAtRisk };
  }, [requests]);

  // Open drawer
  const openDrawer = (req, mode = null) => {
    setSelected(req);
    setActionMode(mode);
    setActionReason("");
    setDrawerOpen(true);
  };

  // Close drawer
  const closeDrawer = () => {
    setDrawerOpen(false);
    setSelected(null);
    setActionMode(null);
    setActionReason("");
  };

  // Perform action
  const performAction = (mode) => {
    if (!selected) return;
    if (!actionReason || actionReason.trim().length < 5) {
      alert("Please provide a reason (min 5 characters) for this action.");
      return;
    }

    setRequests((prev) =>
      prev.map((r) =>
        r.id === selected.id
          ? {
              ...r,
              status:
                mode === "approve"
                  ? "approved"
                  : mode === "reject"
                  ? "rejected"
                  : mode === "defer"
                  ? "deferred"
                  : r.status,
              timestamps: {
                ...r.timestamps,
                reviewedAt: new Date().toISOString(),
                finalDecisionAt:
                  mode === "approve" || mode === "reject"
                    ? new Date().toISOString()
                    : r.timestamps.finalDecisionAt,
              },
              timeline: [
                ...r.timeline,
                {
                  ts: new Date().toISOString(),
                  actor: "reviewer.current",
                  action:
                    mode === "approve"
                      ? "Approved"
                      : mode === "reject"
                      ? "Rejected"
                      : mode === "defer"
                      ? "Deferred"
                      : "Requested more evidence",
                  note: actionReason,
                },
              ],
            }
          : r
      )
    );

    console.log(
      `Action performed: ${mode} on ${selected.id} with reason:`,
      actionReason
    );
    closeDrawer();
  };

  // Toggle sort
  const toggleSort = (key) => {
    if (sortKey === key) {
      setSortDir((d) => (d === "asc" ? "desc" : "asc"));
    } else {
      setSortKey(key);
      setSortDir("desc");
    }
  };

  // Executive insights
  const insights = useMemo(() => {
    const moneySaved = requests
      .filter((r) => r.status === "rejected")
      .reduce((s, r) => s + (r.estimatedCost || 0), 0);
    const falseClaims = requests.filter(
      (r) => r.status === "rejected" && r.aiVerdict === "approve"
    ).length;
    const agingTrend = Math.round(
      requests.reduce((s, r) => s + (r.systemSnapshot?.ageYears || 0), 0) /
        requests.length
    );
    return { moneySaved, falseClaims, agingTrend };
  }, [requests]);

  return (
    <div className="p-6 bg-gray-50 min-h-screen">
      {/* Header with KPIs */}
      <div className="mb-6">
        <div className="flex flex-col lg:flex-row lg:items-start lg:justify-between gap-4 mb-4">
          <div>
            <h1 className="text-3xl font-bold text-gray-900">Replacement Decisions</h1>
            <p className="text-sm text-gray-600 mt-1">
              AI-verified hardware replacement approvals with financial impact analysis
            </p>
          </div>
        </div>

        {/* KPI Cards Row */}
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-5 gap-4">
          <div className="bg-white border border-gray-200 rounded-lg p-4 shadow-sm">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-xs text-gray-500 uppercase tracking-wide">Pending Requests</p>
                <p className="text-2xl font-bold text-gray-900 mt-1">{kpis.pending}</p>
              </div>
              <div className="w-12 h-12 bg-yellow-100 rounded-lg flex items-center justify-center">
                <span className="text-2xl">⏳</span>
              </div>
            </div>
          </div>

          <div className="bg-white border border-gray-200 rounded-lg p-4 shadow-sm">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-xs text-gray-500 uppercase tracking-wide">Approved Today</p>
                <p className="text-2xl font-bold text-green-600 mt-1">{kpis.approvedToday}</p>
              </div>
              <div className="w-12 h-12 bg-green-100 rounded-lg flex items-center justify-center">
                <span className="text-2xl">✓</span>
              </div>
            </div>
          </div>

          <div className="bg-white border border-gray-200 rounded-lg p-4 shadow-sm">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-xs text-gray-500 uppercase tracking-wide">Cost at Risk</p>
                <p className="text-2xl font-bold text-red-600 mt-1">{currency(kpis.costAtRisk)}</p>
              </div>
              <div className="w-12 h-12 bg-red-100 rounded-lg flex items-center justify-center">
                <span className="text-2xl">💰</span>
              </div>
            </div>
          </div>

          <div className="bg-white border border-gray-200 rounded-lg p-4 shadow-sm">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-xs text-gray-500 uppercase tracking-wide">Money Saved</p>
                <p className="text-2xl font-bold text-blue-600 mt-1">{currency(insights.moneySaved)}</p>
              </div>
              <div className="w-12 h-12 bg-blue-100 rounded-lg flex items-center justify-center">
                <span className="text-2xl">💵</span>
              </div>
            </div>
            <p className="text-xs text-gray-500 mt-2">Avoided unnecessary replacements</p>
          </div>

          <div className="bg-white border border-gray-200 rounded-lg p-4 shadow-sm">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-xs text-gray-500 uppercase tracking-wide">Avg System Age</p>
                <p className="text-2xl font-bold text-gray-900 mt-1">{insights.agingTrend} yrs</p>
              </div>
              <div className="w-12 h-12 bg-purple-100 rounded-lg flex items-center justify-center">
                <span className="text-2xl">📊</span>
              </div>
            </div>
            <p className="text-xs text-gray-500 mt-2">Hardware aging trend</p>
          </div>
        </div>
      </div>

      {/* Controls */}
      <div className="mb-4 bg-white border border-gray-200 rounded-lg p-4 shadow-sm">
        <div className="flex flex-col lg:flex-row lg:items-center gap-3">
          <div className="flex-1 flex items-center gap-2">
            <div className="relative flex-1">
              <input
                placeholder="Search by request ID, system ID, owner, or requester..."
                value={query}
                onChange={(e) => setQuery(e.target.value)}
                className="w-full px-4 py-2 pl-10 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-transparent"
              />
              <span className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400">
                🔍
              </span>
            </div>
            {query && (
              <button
                onClick={() => setQuery("")}
                className="px-4 py-2 bg-gray-100 hover:bg-gray-200 rounded-lg text-sm font-medium transition-colors"
              >
                Clear
              </button>
            )}
          </div>

          <div className="flex items-center gap-2 flex-wrap">
            <select
              value={statusFilter}
              onChange={(e) => setStatusFilter(e.target.value)}
              className="px-3 py-2 border border-gray-300 rounded-lg bg-white text-sm focus:outline-none focus:ring-2 focus:ring-blue-500"
            >
              <option>All</option>
              <option>pending</option>
              <option>approved</option>
              <option>rejected</option>
              <option>deferred</option>
            </select>

            <select
              value={rootCauseFilter}
              onChange={(e) => setRootCauseFilter(e.target.value)}
              className="px-3 py-2 border border-gray-300 rounded-lg bg-white text-sm focus:outline-none focus:ring-2 focus:ring-blue-500"
            >
              <option>All</option>
              <option>Hardware</option>
              <option>Software</option>
              <option>Security</option>
            </select>

            <div className="h-6 w-px bg-gray-300"></div>

            <button
              onClick={() => toggleSort("confidence")}
              className="px-3 py-2 border border-gray-300 rounded-lg bg-white text-sm hover:bg-gray-50 transition-colors"
            >
              Sort: Confidence {sortKey === "confidence" && (sortDir === "asc" ? "↑" : "↓")}
            </button>
            <button
              onClick={() => toggleSort("estimatedCost")}
              className="px-3 py-2 border border-gray-300 rounded-lg bg-white text-sm hover:bg-gray-50 transition-colors"
            >
              Sort: Cost {sortKey === "estimatedCost" && (sortDir === "asc" ? "↑" : "↓")}
            </button>
          </div>
        </div>
      </div>

      {/* Main Table */}
      <div className="bg-white border border-gray-200 rounded-lg shadow-sm overflow-hidden">
        <div className="overflow-x-auto">
          <table className="min-w-full divide-y divide-gray-200">
            <thead className="bg-gray-50">
              <tr>
                <th className="px-4 py-3 text-left text-xs font-semibold text-gray-600 uppercase tracking-wider">
                  Request ID
                </th>
                <th className="px-4 py-3 text-left text-xs font-semibold text-gray-600 uppercase tracking-wider">
                  System ID
                </th>
                <th className="px-4 py-3 text-left text-xs font-semibold text-gray-600 uppercase tracking-wider">
                  Owner
                </th>
                <th className="px-4 py-3 text-left text-xs font-semibold text-gray-600 uppercase tracking-wider">
                  AI Verdict
                </th>
                <th className="px-4 py-3 text-left text-xs font-semibold text-gray-600 uppercase tracking-wider">
                  Root Cause
                </th>
                <th className="px-4 py-3 text-right text-xs font-semibold text-gray-600 uppercase tracking-wider">
                  Confidence
                </th>
                <th className="px-4 py-3 text-right text-xs font-semibold text-gray-600 uppercase tracking-wider">
                  Cost
                </th>
                <th className="px-4 py-3 text-left text-xs font-semibold text-gray-600 uppercase tracking-wider">
                  Risk
                </th>
                <th className="px-4 py-3 text-left text-xs font-semibold text-gray-600 uppercase tracking-wider">
                  Status
                </th>
                <th className="px-4 py-3 text-left text-xs font-semibold text-gray-600 uppercase tracking-wider">
                  Actions
                </th>
              </tr>
            </thead>
            <tbody className="bg-white divide-y divide-gray-200">
              {visible.length === 0 ? (
                <tr>
                  <td
                    colSpan={10}
                    className="px-4 py-12 text-center text-sm text-gray-500"
                  >
                    <div className="flex flex-col items-center justify-center gap-2">
                      <span className="text-4xl">🔍</span>
                      <p className="font-medium">No replacement requests found</p>
                      <p className="text-xs">Try adjusting your filters or search query</p>
                    </div>
                  </td>
                </tr>
              ) : (
                visible.map((r) => (
                  <tr key={r.id} className="hover:bg-gray-50 transition-colors">
                    <td className="px-4 py-4">
                      <button
                        onClick={() => openDrawer(r)}
                        className="text-sm font-semibold text-blue-600 hover:text-blue-800 hover:underline"
                      >
                        {r.id}
                      </button>
                      <p className="text-xs text-gray-500 mt-0.5">
                        {relativeTime(r.timestamps.requestedAt)}
                      </p>
                    </td>
                    <td className="px-4 py-4 text-sm font-medium text-gray-900">
                      {r.systemId}
                    </td>
                    <td className="px-4 py-4">
                      <p className="text-sm text-gray-900">{r.owner}</p>
                      <p className="text-xs text-gray-500">by {r.requestedBy}</p>
                    </td>
                    <td className="px-4 py-4">
                      <span
                        className={`inline-flex items-center px-2.5 py-1 rounded-full text-xs font-semibold ${
                          r.aiVerdict === "approve"
                            ? "bg-green-100 text-green-800 border border-green-200"
                            : "bg-red-100 text-red-800 border border-red-200"
                        }`}
                      >
                        {r.aiVerdict === "approve" ? "✓" : "✕"} {r.aiVerdict.toUpperCase()}
                      </span>
                    </td>
                    <td className="px-4 py-4">
                      <span className="text-sm text-gray-900">{r.rootCause}</span>
                    </td>
                    <td className="px-4 py-4 text-right">
                      <div className="flex items-center justify-end gap-2">
                        <div className="w-16 bg-gray-200 rounded-full h-2">
                          <div
                            className={`h-2 rounded-full ${
                              r.confidence >= 80
                                ? "bg-green-500"
                                : r.confidence >= 60
                                ? "bg-yellow-500"
                                : "bg-red-500"
                            }`}
                            style={{ width: `${r.confidence}%` }}
                          ></div>
                        </div>
                        <span className="text-sm font-semibold text-gray-900">
                          {r.confidence}%
                        </span>
                      </div>
                    </td>
                    <td className="px-4 py-4 text-right text-sm font-semibold text-gray-900">
                      {currency(r.estimatedCost)}
                    </td>
                    <td className="px-4 py-4">
                      <span
                        className={`inline-flex px-2.5 py-1 rounded-full text-xs font-semibold ${riskBadgeClass(
                          r.riskIfDelayed
                        )}`}
                      >
                        {r.riskIfDelayed}
                      </span>
                    </td>
                    <td className="px-4 py-4">
                      <span
                        className={`inline-flex px-2.5 py-1 rounded-full text-xs font-semibold ${statusBadgeClass(
                          r.status
                        )}`}
                      >
                        {r.status.toUpperCase()}
                      </span>
                    </td>
                    <td className="px-4 py-4">
                      <div className="flex gap-2">
                        <button
                          onClick={() => openDrawer(r)}
                          className="px-3 py-1.5 border border-gray-300 rounded-md text-xs font-medium hover:bg-gray-50 transition-colors"
                        >
                          View Details
                        </button>
                        {r.status === "pending" && (
                          <button
                            onClick={() => openDrawer(r, "approve")}
                            className="px-3 py-1.5 bg-green-600 text-white rounded-md text-xs font-medium hover:bg-green-700 transition-colors"
                          >
                            Quick Approve
                          </button>
                        )}
                      </div>
                    </td>
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>
      </div>

      {/* Decision Drawer */}
      {drawerOpen && selected && (
        <div className="fixed inset-0 z-50 flex">
          <div
            className="absolute inset-0 bg-black/40 backdrop-blur-sm"
            onClick={closeDrawer}
          />
          <aside className="ml-auto w-full sm:w-[800px] bg-white shadow-2xl overflow-y-auto relative">
            <div className="sticky top-0 z-10 bg-white border-b border-gray-200 p-6 shadow-sm">
              <div className="flex items-start justify-between">
                <div>
                  <div className="flex items-center gap-2">
                    <span
                      className={`inline-flex px-3 py-1 rounded-full text-xs font-semibold ${statusBadgeClass(
                        selected.status
                      )}`}
                    >
                      {selected.status.toUpperCase()}
                    </span>
                    <h2 className="text-xl font-bold text-gray-900">{selected.id}</h2>
                  </div>
                  <p className="text-sm text-gray-600 mt-1">
                    System: <span className="font-semibold">{selected.systemId}</span> • 
                    Owner: {selected.owner}
                  </p>
                  <p className="text-xs text-gray-500 mt-1">
                    Requested by {selected.requestedBy} • {relativeTime(selected.timestamps.requestedAt)}
                  </p>
                </div>
                <button
                  onClick={closeDrawer}
                  className="px-4 py-2 text-sm font-medium text-gray-700 bg-gray-100 hover:bg-gray-200 rounded-lg transition-colors"
                >
                  Close
                </button>
              </div>
            </div>

            <div className="p-6 space-y-6">
              {/* AI Verdict Section */}
              <section className="bg-gradient-to-br from-blue-50 to-indigo-50 border border-blue-200 rounded-lg p-5">
                <div className="flex items-start justify-between">
                  <div>
                    <div className="flex items-center gap-2 mb-3">
                      <span className="text-2xl">🤖</span>
                      <h3 className="text-lg font-bold text-gray-900">AI Decision Verdict</h3>
                    </div>
                    <div className="flex items-center gap-4">
                      <span
                        className={`inline-flex items-center px-4 py-2 rounded-lg text-sm font-bold ${
                          selected.aiVerdict === "approve"
                            ? "bg-green-600 text-white"
                            : "bg-red-600 text-white"
                        }`}
                      >
                        {selected.aiVerdict === "approve" ? "✓ APPROVE" : "✕ REJECT"}
                      </span>
                      <div>
                        <p className="text-xs text-gray-600">Confidence Score</p>
                        <div className="flex items-center gap-2 mt-1">
                          <div className="w-32 bg-gray-300 rounded-full h-3">
                            <div
                              className={`h-3 rounded-full ${
                                selected.confidence >= 80
                                  ? "bg-green-500"
                                  : selected.confidence >= 60
                                  ? "bg-yellow-500"
                                  : "bg-red-500"
                              }`}
                              style={{ width: `${selected.confidence}%` }}
                            ></div>
                          </div>
                          <span className="text-lg font-bold text-gray-900">
                            {selected.confidence}%
                          </span>
                        </div>
                      </div>
                    </div>
                    <p className="text-sm text-gray-700 mt-4 leading-relaxed">
                      {selected.aiVerdict === "approve"
                        ? "AI recommends replacement due to strong hardware failure signals, degrading performance trends, and historical failure patterns matching critical thresholds."
                        : "AI recommends rejecting replacement. Analysis indicates software misconfiguration or environmental factors as primary cause. Hardware metrics remain within acceptable ranges."}
                    </p>
                  </div>
                </div>
              </section>

              {/* System Snapshot */}
              <section className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div className="bg-white border border-gray-200 rounded-lg p-5">
                  <h3 className="text-sm font-bold text-gray-900 mb-4 flex items-center gap-2">
                    <span>💻</span> System Information
                  </h3>
                  <div className="space-y-3">
                    <div className="flex justify-between items-center">
                      <span className="text-sm text-gray-600">System ID</span>
                      <span className="text-sm font-semibold text-gray-900">{selected.systemId}</span>
                    </div>
                    <div className="flex justify-between items-center">
                      <span className="text-sm text-gray-600">System Age</span>
                      <span className="text-sm font-semibold text-gray-900">
                        {selected.systemSnapshot?.ageYears ?? "—"} years
                      </span>
                    </div>
                    <div className="flex justify-between items-center">
                      <span className="text-sm text-gray-600">Warranty Status</span>
                      <span className={`text-sm font-semibold ${
                        selected.systemSnapshot?.warrantyUntil ? "text-green-600" : "text-red-600"
                      }`}>
                        {selected.systemSnapshot?.warrantyUntil
                          ? `Until ${new Date(selected.systemSnapshot.warrantyUntil).toLocaleDateString()}`
                          : "Expired"}
                      </span>
                    </div>
                    <div className="flex justify-between items-center">
                      <span className="text-sm text-gray-600">Root Cause</span>
                      <span className="inline-flex px-2.5 py-1 rounded-full text-xs font-semibold bg-gray-100 text-gray-800">
                        {selected.rootCause}
                      </span>
                    </div>
                  </div>
                </div>

                <div className="bg-white border border-gray-200 rounded-lg p-5">
                  <h3 className="text-sm font-bold text-gray-900 mb-4 flex items-center gap-2">
                    <span>📉</span> Health Trend
                  </h3>
                  <div className="space-y-2">
                    {selected.systemSnapshot?.healthTrend?.map((h, i) => (
                      <div key={i} className="flex items-center gap-3">
                        <span className="text-xs text-gray-500 w-8">{h.label}</span>
                        <div className="flex-1 bg-gray-200 rounded-full h-2">
                          <div
                            className={`h-2 rounded-full ${
                              h.value >= 70
                                ? "bg-green-500"
                                : h.value >= 50
                                ? "bg-yellow-500"
                                : "bg-red-500"
                            }`}
                            style={{ width: `${h.value}%` }}
                          ></div>
                        </div>
                        <span className="text-xs font-semibold text-gray-900 w-8">
                          {h.value}
                        </span>
                      </div>
                    ))}
                  </div>
                  <p className="text-xs text-gray-500 mt-3">
                    {selected.systemSnapshot?.healthTrend?.[0]?.value > 
                     selected.systemSnapshot?.healthTrend?.[selected.systemSnapshot.healthTrend.length - 1]?.value
                      ? "⚠️ Declining health trend detected"
                      : "✓ Stable or improving health"}
                  </p>
                </div>
              </section>

              {/* Evidence Summary */}
              <section>
                <h3 className="text-lg font-bold text-gray-900 mb-4">Evidence Analysis</h3>
                <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                  <div className="bg-white border border-gray-200 rounded-lg p-4">
                    <div className="flex items-center gap-2 mb-3">
                      <span className="text-xl">🔧</span>
                      <h4 className="text-sm font-bold text-gray-900">Hardware</h4>
                    </div>
                    {selected.evidence.hardware.length === 0 || selected.evidence.hardware[0] === "N/A" ? (
                      <p className="text-xs text-gray-500 italic">No hardware issues detected</p>
                    ) : (
                      <ul className="text-sm text-gray-700 space-y-2">
                        {selected.evidence.hardware.map((e, i) => (
                          <li key={i} className="flex gap-2">
                            <span className="text-red-500 flex-shrink-0">•</span>
                            <span>{e}</span>
                          </li>
                        ))}
                      </ul>
                    )}
                  </div>

                  <div className="bg-white border border-gray-200 rounded-lg p-4">
                    <div className="flex items-center gap-2 mb-3">
                      <span className="text-xl">💾</span>
                      <h4 className="text-sm font-bold text-gray-900">Software</h4>
                    </div>
                    {selected.evidence.software.length === 0 || selected.evidence.software[0] === "N/A" ? (
                      <p className="text-xs text-gray-500 italic">No software issues detected</p>
                    ) : (
                      <ul className="text-sm text-gray-700 space-y-2">
                        {selected.evidence.software.map((e, i) => (
                          <li key={i} className="flex gap-2">
                            <span className="text-yellow-500 flex-shrink-0">•</span>
                            <span>{e}</span>
                          </li>
                        ))}
                      </ul>
                    )}
                  </div>

                  <div className="bg-white border border-gray-200 rounded-lg p-4">
                    <div className="flex items-center gap-2 mb-3">
                      <span className="text-xl">🔒</span>
                      <h4 className="text-sm font-bold text-gray-900">Security</h4>
                    </div>
                    {selected.evidence.security.length === 0 || selected.evidence.security[0] === "N/A" ? (
                      <p className="text-xs text-gray-500 italic">No security issues detected</p>
                    ) : (
                      <ul className="text-sm text-gray-700 space-y-2">
                        {selected.evidence.security.map((e, i) => (
                          <li key={i} className="flex gap-2">
                            <span className="text-blue-500 flex-shrink-0">•</span>
                            <span>{e}</span>
                          </li>
                        ))}
                      </ul>
                    )}
                  </div>
                </div>
              </section>

              {/* Financial Impact */}
              <section className="bg-gradient-to-br from-green-50 to-emerald-50 border border-green-200 rounded-lg p-5">
                <h3 className="text-lg font-bold text-gray-900 mb-4 flex items-center gap-2">
                  <span>💰</span> Financial Impact Analysis
                </h3>
                <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                  <div>
                    <p className="text-xs text-gray-600 mb-1">Replacement Cost</p>
                    <p className="text-2xl font-bold text-gray-900">
                      {currency(selected.financial.replaceEstimate || selected.estimatedCost)}
                    </p>
                  </div>
                  <div>
                    <p className="text-xs text-gray-600 mb-1">Repair Alternative</p>
                    <p className="text-2xl font-bold text-blue-600">
                      {currency(selected.financial.repairEstimate)}
                    </p>
                    <p className="text-xs text-gray-500 mt-1">
                      {Math.round((1 - selected.financial.repairEstimate / selected.estimatedCost) * 100)}% cheaper
                    </p>
                  </div>
                  <div>
                    <p className="text-xs text-gray-600 mb-1">Downtime Risk / Hour</p>
                    <p className="text-2xl font-bold text-red-600">
                      {currency(selected.financial.downtimeCostPerHour)}
                    </p>
                  </div>
                </div>
                <div className="mt-4 p-3 bg-white rounded-lg border border-green-300">
                  <p className="text-sm text-gray-700">
                    <span className="font-semibold">ROI Analysis:</span>{" "}
                    {selected.estimatedCost > selected.financial.downtimeCostPerHour * 24 * 30
                      ? "High-cost replacement. Consider repair if downtime risk is manageable."
                      : "Replacement recommended to minimize extended downtime costs and operational disruption."}
                  </p>
                </div>
              </section>

              {/* Action Buttons */}
              {selected.status === "pending" && (
                <section className="bg-white border-2 border-blue-200 rounded-lg p-5">
                  <h3 className="text-lg font-bold text-gray-900 mb-4">Reviewer Actions</h3>
                  <div className="flex flex-wrap gap-3 mb-4">
                    <button
                      onClick={() => {
                        setActionMode("approve");
                        setActionReason("");
                      }}
                      className="px-5 py-2.5 bg-green-600 text-white rounded-lg text-sm font-semibold hover:bg-green-700 transition-colors shadow-sm"
                    >
                      ✓ Approve Replacement
                    </button>
                    <button
                      onClick={() => {
                        setActionMode("reject");
                        setActionReason("");
                      }}
                      className="px-5 py-2.5 bg-red-600 text-white rounded-lg text-sm font-semibold hover:bg-red-700 transition-colors shadow-sm"
                    >
                      ✕ Reject Request
                    </button>
                    <button
                      onClick={() => {
                        setActionMode("defer");
                        setActionReason("");
                      }}
                      className="px-5 py-2.5 bg-gray-600 text-white rounded-lg text-sm font-semibold hover:bg-gray-700 transition-colors shadow-sm"
                    >
                      ⏸ Defer Decision
                    </button>
                    <button
                      onClick={() => {
                        setActionMode("evidence");
                        setActionReason("");
                      }}
                      className="px-5 py-2.5 bg-yellow-600 text-white rounded-lg text-sm font-semibold hover:bg-yellow-700 transition-colors shadow-sm"
                    >
                      🔍 Request More Evidence
                    </button>
                  </div>

                  {actionMode && (
                    <div className="mt-4 p-4 bg-gray-50 rounded-lg border border-gray-200">
                      <div className="mb-3">
                        <p className="text-sm font-semibold text-gray-900">
                          Action: <span className="capitalize text-blue-600">{actionMode}</span>
                        </p>
                        <p className="text-xs text-gray-600 mt-1">
                          Please provide your rationale for this decision (minimum 5 characters)
                        </p>
                      </div>
                      <textarea
                        value={actionReason}
                        onChange={(e) => setActionReason(e.target.value)}
                        placeholder="Enter detailed reason for this decision..."
                        className="w-full border border-gray-300 rounded-lg p-3 min-h-[100px] bg-white focus:outline-none focus:ring-2 focus:ring-blue-500 text-sm"
                      />
                      <div className="flex gap-2 justify-end mt-3">
                        <button
                          onClick={() => {
                            setActionMode(null);
                            setActionReason("");
                          }}
                          className="px-4 py-2 border border-gray-300 rounded-lg text-sm font-medium hover:bg-gray-50 transition-colors"
                        >
                          Cancel
                        </button>
                        <button
                          onClick={() => performAction(actionMode)}
                          className="px-4 py-2 bg-blue-600 text-white rounded-lg text-sm font-semibold hover:bg-blue-700 transition-colors"
                        >
                          Submit Decision
                        </button>
                      </div>
                    </div>
                  )}
                </section>
              )}

              {/* Audit Trail */}
              <section>
                <h3 className="text-lg font-bold text-gray-900 mb-4 flex items-center gap-2">
                  <span>📋</span> Audit Trail
                </h3>
                <div className="space-y-3">
                  {selected.timeline.map((t, i) => (
                    <div
                      key={i}
                      className="bg-white border border-gray-200 rounded-lg p-4 hover:border-gray-300 transition-colors"
                    >
                      <div className="flex items-start justify-between">
                        <div className="flex-1">
                          <div className="flex items-center gap-2">
                            <span className="inline-flex px-2 py-1 rounded text-xs font-semibold bg-blue-100 text-blue-800">
                              {t.actor}
                            </span>
                            <span className="text-sm font-semibold text-gray-900">{t.action}</span>
                          </div>
                          <p className="text-sm text-gray-600 mt-2">{t.note}</p>
                        </div>
                        <span className="text-xs text-gray-400 flex-shrink-0 ml-4">
                          {relativeTime(t.ts)}
                        </span>
                      </div>
                    </div>
                  ))}
                </div>
              </section>
            </div>
          </aside>
        </div>
      )}
    </div>
  );
}
